// 1. Entity — the table
@Entity(tableName = "user")
data class User(
  @PrimaryKey(autoGenerate = true) val id: Int = 0,
  val name: String,
  val email: String?,
  @ColumnInfo(name = "joined_at") val joinedAt: Long = System.currentTimeMillis(),
)

// 2. DAO — how you interact with the table
@Dao
interface UserDao {
  // Flow — emits a new list whenever the user table changes anywhere
  @Query("SELECT * FROM user ORDER BY name")
  fun observeUsers(): Flow<List<User>>

  @Query("SELECT * FROM user WHERE id = :id")
  suspend fun getById(id: Int): User?

  @Insert(onConflict = OnConflictStrategy.REPLACE)
  suspend fun upsert(user: User)

  @Insert(onConflict = OnConflictStrategy.REPLACE)
  suspend fun upsertAll(users: List<User>)

  @Query("DELETE FROM user WHERE id = :id")
  suspend fun deleteById(id: Int)

  // Transaction — the queries run atomically
  @Transaction
  suspend fun replaceAll(users: List<User>) {
    clearAll()
    upsertAll(users)
  }

  @Query("DELETE FROM user")
  suspend fun clearAll()
}

// 3. Database — the entry point
@Database(entities = [User::class], version = 1, exportSchema = true)
abstract class AppDb : RoomDatabase() {
  abstract fun userDao(): UserDao
}

// 4. Building it (once, at app start)
val db: AppDb = Room.databaseBuilder(context, AppDb::class.java, "app.db").build()
val userDao = db.userDao()

// Many-to-one: each Order belongs to one User
@Entity(tableName = "order", foreignKeys = [
  ForeignKey(entity = User::class, parentColumns = ["id"], childColumns = ["userId"])
])
data class Order(
  @PrimaryKey(autoGenerate = true) val id: Int = 0,
  val userId: Int,
  val amount: Double,
)

// A join result — User + their Orders
data class UserWithOrders(
  @Embedded val user: User,
  @Relation(parentColumn = "id", entityColumn = "userId")
  val orders: List<Order>,
)

@Dao
interface UserOrdersDao {
  @Transaction  // guarantees consistent read across the join
  @Query("SELECT * FROM user")
  fun observeUsersWithOrders(): Flow<List<UserWithOrders>>
}

// You bumped version = 1 to version = 2. What happens?
// - If you provide a Migration: Room runs your SQL, keeps user data.
// - If you call .fallbackToDestructiveMigration(): Room drops the DB.
//   USER DATA IS GONE. Never do this in production.

val MIGRATION_1_2 = object : Migration(1, 2) {
  override fun migrate(db: SupportSQLiteDatabase) {
    // Add a column to an existing table — user data preserved
    db.execSQL("ALTER TABLE user ADD COLUMN age INTEGER NOT NULL DEFAULT 0")
  }
}

val db = Room.databaseBuilder(context, AppDb::class.java, "app.db")
  .addMigrations(MIGRATION_1_2)
  .build()

// For complex changes (rename, split table), you often need multiple ALTER TABLEs
// or the classic 'create new table, copy data, drop old, rename'. Always test on
// a real prod-shaped DB before shipping.

